import LogPanel from '@/components/LogPanel.vue';
import { validateImage, fileToDataURL, getImageDimensions, formatFileSize } from '@/utils/imageUtils';
import { analyzeImageMock as analyzeImage, checkHealth } from '@/api/pigModel';
export default {
  name: 'App',
  components: {
    LogPanel
  },
  data() {
    return {
      checkingService: false,
      isDragging: false,
      hoveredBox: null,
      animatedCount: 0
    };
  },
  computed: {
    hasImage() {
      return this.$store.getters.hasImage;
    },
    hasResult() {
      return this.$store.getters.hasResult;
    },
    previewUrl() {
      return this.$store.state.previewUrl;
    },
    imageMeta() {
      return this.$store.state.imageMeta;
    },
    isAnalyzing() {
      return this.$store.state.isAnalyzing;
    },
    uploadProgress() {
      return this.$store.state.uploadProgress;
    },
    result() {
      return this.$store.state.result;
    },
    pigCount() {
      return this.$store.getters.pigCount;
    },
    confidencePct() {
      return this.$store.getters.confidencePct;
    },
    inferenceTime() {
      return this.$store.getters.inferenceTime;
    },
    year() {
      return new Date().getFullYear();
    },
    confClass() {
      const p = this.confidencePct;
      if (p >= 85) return 'conf-high';
      if (p >= 65) return 'conf-mid';
      return 'conf-low';
    },
    serviceClass() {
      const s = this.$store.state.serviceOnline;
      if (s === null) return 'service-unknown';
      return s ? 'service-online' : 'service-offline';
    },
    serviceLabel() {
      if (this.checkingService) return '检测中…';
      const s = this.$store.state.serviceOnline;
      if (s === null) return '状态未知';
      return s ? '服务正常' : '离线 / Mock';
    },
    statCards() {
      return [{
        icon: '🐷',
        label: '预测数量',
        value: this.hasResult ? this.pigCount : null,
        unit: this.hasResult ? '头' : null,
        cls: '',
        active: this.hasResult
      }, {
        icon: '⚡',
        label: '处理耗时',
        value: this.inferenceTime,
        unit: this.inferenceTime ? 'ms' : null,
        cls: '',
        active: !!this.inferenceTime
      }, {
        icon: '🎯',
        label: '平均置信度',
        value: this.hasResult ? this.confidencePct + '%' : null,
        unit: null,
        cls: this.confClass,
        active: this.hasResult
      }, {
        icon: '📐',
        label: '图像尺寸',
        value: this.imageMeta ? this.imageMeta.width + '×' + this.imageMeta.height : null,
        unit: null,
        cls: 'stat-sm',
        active: !!this.imageMeta
      }];
    }
  },
  watch: {
    pigCount(val) {
      if (val === null) {
        this.animatedCount = 0;
        return;
      }
      this.animateNumber(val);
    },
    hasResult(val) {
      if (val) this.$nextTick(() => this.drawBoxesAnimated());
    }
  },
  created() {
    this.checkServiceHealth();
  },
  mounted() {
    window.addEventListener('mousemove', this.onMouseMove);
  },
  beforeDestroy() {
    window.removeEventListener('mousemove', this.onMouseMove);
  },
  methods: {
    onMouseMove(e) {
      const mx = e.clientX / window.innerWidth - 0.5;
      const my = e.clientY / window.innerHeight - 0.5;
      const o1 = document.querySelector('.orb-1');
      const o2 = document.querySelector('.orb-2');
      if (o1) o1.style.transform = 'translate(' + mx * 30 + 'px,' + my * 30 + 'px)';
      if (o2) o2.style.transform = 'translate(' + -mx * 20 + 'px,' + -my * 20 + 'px)';
    },
    cardFloatIn(e) {
      const card = e.currentTarget;
      card._tiltFn = ev => {
        const r = card.getBoundingClientRect();
        const cx = (ev.clientX - r.left) / r.width - 0.5;
        const cy = (ev.clientY - r.top) / r.height - 0.5;
        card.style.transform = 'perspective(800px) rotateX(' + -cy * 3 + 'deg) rotateY(' + cx * 3 + 'deg) translateY(-2px)';
      };
      card.addEventListener('mousemove', card._tiltFn);
    },
    cardFloatOut(e) {
      const card = e.currentTarget;
      if (card._tiltFn) card.removeEventListener('mousemove', card._tiltFn);
      card.style.transform = '';
    },
    onTopFileChange(e) {
      const f = e.target.files[0];
      if (f) this.processFile(f);
      e.target.value = '';
    },
    onDropInputChange(e) {
      const f = e.target.files[0];
      if (f) this.processFile(f);
      e.target.value = '';
    },
    onDrop(e) {
      this.isDragging = false;
      const f = e.dataTransfer.files[0];
      if (f) this.processFile(f);
    },
    async processFile(file) {
      const {
        valid,
        error
      } = validateImage(file);
      if (!valid) {
        this.$store.commit('ADD_LOG', {
          msg: error,
          type: 'error'
        });
        return;
      }
      const dataURL = await fileToDataURL(file);
      const dim = await getImageDimensions(dataURL);
      const meta = {
        name: file.name,
        size: formatFileSize(file.size),
        width: dim.width,
        height: dim.height
      };
      this.$store.commit('SET_IMAGE', {
        file,
        previewUrl: dataURL,
        meta
      });
      this.$store.commit('ADD_LOG', {
        msg: '已加载：' + file.name + '（' + meta.size + '，' + meta.width + '×' + meta.height + '）',
        type: 'info'
      });
    },
    clearImage() {
      this.$store.commit('CLEAR_IMAGE');
      this.$store.commit('ADD_LOG', {
        msg: '已清除图片',
        type: 'info'
      });
      this.clearCanvas();
    },
    async runAnalysis() {
      if (!this.hasImage || this.isAnalyzing) return;
      const btn = this.$refs.analyzeBtn;
      if (btn) {
        btn.style.transform = 'scale(0.93)';
        setTimeout(() => {
          btn.style.transform = '';
        }, 150);
      }
      this.$store.commit('SET_ANALYZING', true);
      this.$store.commit('SET_PROGRESS', 0);
      this.$store.commit('ADD_LOG', {
        msg: '发送至数猪大模型…',
        type: 'info'
      });
      try {
        const result = await analyzeImage(this.$store.state.imageFile, p => this.$store.commit('SET_PROGRESS', p));
        this.$store.commit('SET_RESULT', result);
        this.$store.commit('SET_PROGRESS', 100);
        this.$store.commit('ADD_LOG', {
          msg: '识别完成：检测到 ' + result.count + ' 头猪',
          type: 'success'
        });
        this.$store.commit('ADD_LOG', {
          msg: '置信度 ' + Math.round(result.confidence * 100) + '%' + (result.inferenceTime ? '  耗时 ' + result.inferenceTime + 'ms' : ''),
          type: 'success'
        });
      } catch (err) {
        this.$store.commit('ADD_LOG', {
          msg: '识别失败：' + err.message,
          type: 'error'
        });
      } finally {
        this.$store.commit('SET_ANALYZING', false);
      }
    },
    onResultImgLoad() {
      if (this.hasResult) this.drawBoxesAnimated();
    },
    drawBoxesAnimated() {
      const canvas = this.$refs.boxCanvas;
      const img = this.$refs.baseImg;
      if (!canvas || !img || !this.hasResult) return;
      const boxes = this.result && this.result.boxes ? this.result.boxes : [];
      canvas.width = img.clientWidth;
      canvas.height = img.clientHeight;
      const ctx = canvas.getContext('2d');
      let prog = 0;
      const total = 60;
      const draw = () => {
        prog++;
        const t = Math.min(prog / total, 1);
        ctx.clearRect(0, 0, canvas.width, canvas.height);
        boxes.forEach((box, i) => {
          const bd = i / boxes.length * 0.4;
          const lt = Math.max(0, Math.min(1, (t - bd) / 0.6));
          if (lt <= 0) return;
          const c = this.resolveCoords(box, canvas);
          const w = c.x2 - c.x1;
          const h = c.y2 - c.y1;
          const isH = this.hoveredBox === i;
          const col = isH ? 'rgba(255,149,0,' + lt + ')' : 'rgba(52,199,89,' + lt + ')';
          ctx.save();
          ctx.strokeStyle = col;
          ctx.lineWidth = isH ? 2.5 : 1.8;
          ctx.shadowColor = col;
          ctx.shadowBlur = isH ? 10 : 5;
          ctx.globalAlpha = lt;
          ctx.strokeRect(c.x1, c.y1, w, h);
          ctx.restore();
          if (lt > 0.6) {
            const la = (lt - 0.6) / 0.4;
            ctx.save();
            ctx.globalAlpha = la;
            const label = i + 1 + '  ' + (box.score * 100).toFixed(0) + '%';
            ctx.font = 'bold 11px -apple-system,monospace';
            const tw = ctx.measureText(label).width;
            ctx.fillStyle = isH ? 'rgba(255,149,0,0.88)' : 'rgba(52,199,89,0.88)';
            ctx.beginPath();
            ctx.roundRect(c.x1, c.y1 - 22, tw + 12, 20, 4);
            ctx.fill();
            ctx.fillStyle = '#fff';
            ctx.fillText(label, c.x1 + 6, c.y1 - 7);
            ctx.restore();
          }
        });
        if (prog < total) requestAnimationFrame(draw);
      };
      requestAnimationFrame(draw);
    },
    clearCanvas() {
      const c = this.$refs.boxCanvas;
      if (c) c.getContext('2d').clearRect(0, 0, c.width, c.height);
    },
    resolveCoords(box, canvas) {
      const isN = box.x1 <= 1 && box.y1 <= 1;
      const sw = canvas.width;
      const sh = canvas.height;
      const mw = this.imageMeta && this.imageMeta.width || 1;
      const mh = this.imageMeta && this.imageMeta.height || 1;
      if (isN) return {
        x1: box.x1 * sw,
        y1: box.y1 * sh,
        x2: (box.x1 + box.x2) * sw,
        y2: (box.y1 + box.y2) * sh
      };
      return {
        x1: box.x1 / mw * sw,
        y1: box.y1 / mh * sh,
        x2: box.x2 / mw * sw,
        y2: box.y2 / mh * sh
      };
    },
    onRowHover(i) {
      this.hoveredBox = i;
      this.$nextTick(() => this.drawBoxesAnimated());
    },
    animateNumber(target) {
      const dur = 800;
      const start = Date.now();
      const tick = () => {
        const t = Math.min((Date.now() - start) / dur, 1);
        this.animatedCount = Math.round(target * (1 - Math.pow(1 - t, 4)));
        if (t < 1) requestAnimationFrame(tick);
      };
      requestAnimationFrame(tick);
    },
    getConfClass(score) {
      if (score >= 0.85) return 'conf-high';
      if (score >= 0.65) return 'conf-mid';
      return 'conf-low';
    },
    formatCoord(box) {
      const isN = box.x1 <= 1 && box.y1 <= 1;
      const w = this.imageMeta && this.imageMeta.width || 1;
      const h = this.imageMeta && this.imageMeta.height || 1;
      if (isN) return Math.round(box.x1 * w) + ', ' + Math.round(box.y1 * h) + ', ' + Math.round((box.x1 + box.x2) * w) + ', ' + Math.round((box.y1 + box.y2) * h);
      return Math.round(box.x1) + ', ' + Math.round(box.y1) + ', ' + Math.round(box.x2) + ', ' + Math.round(box.y2);
    },
    async checkServiceHealth() {
      this.checkingService = true;
      try {
        const online = await checkHealth();
        this.$store.commit('SET_SERVICE_STATUS', online);
        this.$store.commit('ADD_LOG', {
          msg: online ? '服务在线' : '服务未响应（Mock 模式）',
          type: online ? 'success' : 'warn'
        });
      } catch {
        this.$store.commit('SET_SERVICE_STATUS', false);
      } finally {
        this.checkingService = false;
      }
    }
  }
};
